import modal
import os

app = modal.App("check-volume")
volume = modal.Volume.from_name("text-index-volume", environment_name="modal-vsdatagen")

@app.function(volumes={"/data": volume})
def check_vol():
    if os.path.exists("/data/index"):
        files = os.listdir("/data/index")
        print(f"Files in /data/index: {files}")
        for f in files:
            with open(f"/data/index/{f}", "r") as file:
                print(f"{f}: {file.read()}")
    else:
        print("/data/index does not exist")

@app.local_entrypoint()
def main():
    check_vol.remote()
